import React from 'react';
import styled from 'styled-components';
import {NavLink, Router, Routes, Route, Outlet } from "react-router-dom";
//import img from './tom.jpg';

import App from './App.jsx';
import Home from './0home/home.jsx';

const SWrapper = styled.div`
display: grid;
grid-template-columns:repeat(12, 8.333%);  
grid-template-rows:repeat(12, 55px); 
background: red ;
color: black ;
font-family: 'TopSecretWoff2' ;

`
const SNavLink = styled(NavLink)`
grid-area: 1/1/13/13; 
display: grid;
grid-template-columns:repeat(12, 8.333%);  
grid-template-rows:repeat(12, 8.333%); 
text-decoration:none;
background: black ;
`


const Wrapper = () => {
  return (

<SWrapper>
<Router>
<SNavLink to="app">
<Routes>
<Route path='app' element={<App/>}>
<Route index element={<Home/>}/>
</Route>
</Routes>
 </SNavLink> 
 <Outlet />  
 </Router>
</SWrapper>
  );
};

export default Wrapper;
